INSERT INTO position_categories (positionId, name) VALUES (90002, 'Görev Bilinci');
SET @categoryId = LAST_INSERT_ID();
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '1', 'Yaptığı işi en iyi şekilde yapar. İş disiplini ve görev bilinci yüksektir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '2', 'Sorumluluğundaki işleri, şirket kural ve prosedürlerine uygun bir biçimde gerçekleştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '3', 'İşine, kuruma ve kendisine sunulan kaynaklara zarar verecek hiçbir davranış sergilemez.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '4', 'Ahlaki ve etik değerlere uygun davranır.');

INSERT INTO position_categories (positionId, name) VALUES (90002, 'İletişim Becerisi');
SET @categoryId = LAST_INSERT_ID();
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '1', 'Karşındakini dinler ve verilmek istenen mesajı doğru bir şekilde anlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '2', 'Söylemek istediklerini, açık, kısa ve net bir biçimde karşı tarafa aktarır. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '3', 'İşle ilgili konularla ilgili bilgiyi zamanında aktarır ve paylaşır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '4', 'Her türlü iletişimde empati kurmaya özen gösterir.');

INSERT INTO position_categories (positionId, name) VALUES (90002, 'Analitik Düşünme ve Problem Çözme');
SET @categoryId = LAST_INSERT_ID();
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '1', 'Gelişmekte olan problemleri görür, önleyici davranış geliştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '2', 'Durum ve problem karşısında alacağı hareketin sonucunu bilir. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '3', 'Mevcut sorunu gidermek için alternatif çözüm yolları geliştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '4', 'Benzer sorunlar arasında ilişki kurar; geçmişteki deneyimlerden faydalanır.');

INSERT INTO position_categories (positionId, name) VALUES (90002, 'Kalite Odaklılık');
SET @categoryId = LAST_INSERT_ID();
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '1', 'Mevcut düzen ve iş yapma yöntemine uygun çalışır. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '2', 'Kaliteyi belirlenen standartlara göre uyarlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '3', 'Yapılan işin kalitesini sürekli geliştirmek yönünde çalışır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '4', 'İş yapma yöntemine ilişkin akış ve prosedürlerdeki yeniliklere adapte olur.');

INSERT INTO position_categories (positionId, name) VALUES (90002, 'Takım Çalışması ve İşbirliği');
SET @categoryId = LAST_INSERT_ID();
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '1', 'Çalışma ortamında iyi ilişkiler kurar ve korur. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '2', 'Takım arkadaşlarının yardıma ihtiyacı olduğunda gerekli destekte bulunur.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '3', 'Takım ruhuna uyumlu yaklaşımda bulunur.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '4', 'Takımdaki farklı görüşlere karşı toleranslıdır ve destekleyicidir.');

INSERT INTO position_categories (positionId, name) VALUES (90002, 'Detay Odaklılık');
SET @categoryId = LAST_INSERT_ID();
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '1', 'İşlerin hatasız tamamlanması için çaba sarf eder. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '2', 'Küçük detaylara dikkat eder. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '3', 'İşin inceliklerini öğrenmek ve işin bütününe hâkim olabilmek için sürekli gözlem yapar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '4', 'Hataları, iş çıktıları paylaşılmadan fark eder.');

INSERT INTO position_categories (positionId, name) VALUES (90002, 'Duygularını Kontrol Etme ve Yönetme');
SET @categoryId = LAST_INSERT_ID();
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '1', 'İş ortamında; kızgınlık, korku, kaygı, üzüntü, depresyon, vb. duygularını kontrol eder. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '2', 'Özel hayatında yaşadığı sıkıntıları, iş ortamına en az ölçüde yansıtır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '3', 'Zor çalışma koşullarında ve yoğun mesaide bile başarılı sonuçlar elde edebilir.');

INSERT INTO position_categories (positionId, name) VALUES (90002, 'Sonuç Odaklılık');
SET @categoryId = LAST_INSERT_ID();
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '1', 'Mesleki motivasyonu yüksektir ve işini severek yapar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '2', 'Kendisine verilen işleri takip eder, doğru, eksiksiz ve zamanında sonuçlandırır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '3', 'Her zaman daha iyisini yapmak adına kendisini sürekli geliştirir.');

INSERT INTO position_categories (positionId, name) VALUES (90002, 'İş Disiplini ve Tutum');
SET @categoryId = LAST_INSERT_ID();
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '1', 'Dış görünüşüne, saçına, sakalına, kişisel hijyenine dikkat eder. Eldiven, bone kullanır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '2', 'Şirketin eğitimlerine aktif olarak katılır, atanmış eğitimlerini tamamlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '3', 'Restoran hedeflerinden haberdardır, hedef için elinden gelen gayreti gösterir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '4', 'Mazeret bildirmeden işe gelmemezlik yapmaz. Vardiya ve mola düzenine uyar.');

INSERT INTO position_categories (positionId, name) VALUES (90002, 'Ürün Kalitesi ve Standartlara Uyum');
SET @categoryId = LAST_INSERT_ID();
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '1', 'Ürünleri reçetelere uygun hazırlar. Ürünlerin her seferinde aynı kalite ve tatta olmasını sağlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '2', 'Et pişirme tekniklerine hakimdir. Şirket standartlarına uygun pişirme yapar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '3', 'Patates kızartma standartlarını bilir, doğru şekilde uygular.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '4', 'Peynir çubukları, soğan halkası, nugget vb. ürünleri doğru sürede uygun sıcaklıkta pişirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '5', 'Ekmek kesimini ve burger süslemesini standartlara uygun olarak yapar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '6', 'Kızartma yağı TPM ölçümünü doğru olarak yapar.İç ısı standardını sağlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '7', 'Yağ filtre işlemini standartlara uygun olarak yapar. Koruyucu materyalleri kullanır.');

INSERT INTO position_categories (positionId, name) VALUES (90002, 'Gıda Güvenliği ve Hijyen');
SET @categoryId = LAST_INSERT_ID();
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '1', 'Ürünlerin son kullanma tarihine dikkat eder. Zayii olmasına izin vermez. (FIFO-İlk Giren İlk Çıkar)');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '2', 'Sebzeleri standartlara uygun şekilde yıkar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '3', 'Küçük ekipmanların hijyenini standartlara uygun olarak sağlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '4', 'Gıda güvenliği ve operasyonel prosedür ve talimatları bilir, bunlara uygun hareket eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '5', 'Temizlik kimyasallarını İSG kurallarına uygun şekilde kullanır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '6', 'Çalışma süresince İSG kurallarına uygun hareket eder.');

INSERT INTO position_categories (positionId, name) VALUES (90002, 'İstasyon Yönetimi');
SET @categoryId = LAST_INSERT_ID();
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '1', 'İstasyonlarda doğru ürün miktarının bulunmasına özen gösterir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '2', 'Çalıştığı istasyonların temizliğini ve düzenini sağlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (@categoryId, '3', 'Çalıştığı ekipmanları özenli ve titiz kullanır. Temizliğini yapar.');

